    public static int getCount(int[] a, int[] b, int d) {
        // sort b
        // then for each a with binary search in b find if their exist any element
        // such that their must not be any number between  a[i] - d && d + a[i]
        Arrays.sort(b);
        int cnt = 0;
        for(int n : a) {
            int s = Arrays.binarySearch(b, n-d);
            int e = Arrays.binarySearch(b, n+d);
            if(s >= 0 || e >= 0) continue;
            s = -s;
            e = -e-1;
            if(e < s) cnt++;
        }
        return cnt;
    }
