class Solution {
    public:
        int returnCount(vector<int>& A, vector<int>& B, int d) {
            int ans = 0;
            for (auto& a : A) {
                bool isValid = true;
                for (auto& b : B) {
                    if (abs(a - b) <= d) {
                        isValid = false;
                        continue;
                    }
                }
                if (isValid) ans++;
            }
            return ans;
        }
};

int main() {
    Solution s;
    vector<int> A = {7,6,9}, B = {13,1,4};
    int d = 3;
    int ans = s.returnCount(A, B, d);
    cout << ans;
}
